import React, { useEffect, useState } from 'react';
import api from '../api/client';
import { crmPricing, pricingLastUpdated } from '../data/crmPricing';

const initialForm = {
  name: '',
  description: '',
  base_price: '',
  website_url: ''
};

const defaultCrmRows = [
  {
    name: 'Bitrix24',
    description: 'SaaS-CRM с акцентом на совместную работу и автоматизацию процессов',
    base_price: 1000,
    website_url: 'https://www.bitrix24.ru/'
  },
  {
    name: 'amoCRM',
    description: 'CRM для продаж и коммуникаций с клиентами',
    base_price: 599,
    website_url: 'https://www.amocrm.ru/'
  },
  {
    name: 'Мегаплан',
    description: 'CRM и управление задачами для малого бизнеса',
    base_price: 315,
    website_url: 'https://megaplan.ru/'
  }
];

const CrmPage = () => {
  const [list, setList] = useState([]);
  const [form, setForm] = useState(initialForm);
  const [editingId, setEditingId] = useState(null);
  const [error, setError] = useState('');
  const [info, setInfo] = useState('');

  const load = async () => {
    const { data } = await api.get('/crm');
    setList(data);
  };

  useEffect(() => {
    load();
  }, []);

  const submit = async (event) => {
    event.preventDefault();
    setError('');
    setInfo('');
    try {
      const payload = {
        ...form,
        base_price: Number(form.base_price) || 0
      };

      if (editingId) {
        await api.put(`/crm/${editingId}`, payload);
      } else {
        await api.post('/crm', payload);
      }

      setForm(initialForm);
      setEditingId(null);
      await load();
    } catch (requestError) {
      setError('Не удалось сохранить CRM. Проверьте данные формы.');
    }
  };

  const importDefaultCrm = async () => {
    setError('');
    setInfo('');
    try {
      const existingNames = new Set(list.map((item) => item.name.toLowerCase()));
      const rowsToCreate = defaultCrmRows.filter(
        (row) => !existingNames.has(row.name.toLowerCase())
      );

      await Promise.all(rowsToCreate.map((row) => api.post('/crm', row)));
      await load();

      if (rowsToCreate.length === 0) {
        setInfo('Базовый список уже добавлен.');
      } else {
        setInfo(`Добавлено CRM: ${rowsToCreate.map((row) => row.name).join(', ')}.`);
      }
    } catch (requestError) {
      setError('Не удалось импортировать базовый список CRM.');
    }
  };

  const edit = (item) => {
    setEditingId(item.id);
    setForm({
      name: item.name,
      description: item.description || '',
      base_price: item.base_price,
      website_url: item.website_url || ''
    });
  };

  const remove = async (id) => {
    setError('');
    setInfo('');
    try {
      await api.delete(`/crm/${id}`);
      await load();
    } catch (requestError) {
      setError('Не удалось удалить CRM.');
    }
  };

  return (
    <section>
      <h2>CRM-системы</h2>

      <div className="result-card">
        <p>
          <strong>Актуальные цены по конфигурациям</strong> (обновлено: {pricingLastUpdated})
        </p>
        {crmPricing.map((crm) => (
          <div key={crm.crm} className="pricing-block">
            <p>
              <strong>{crm.crm}</strong> —{' '}
              <a href={crm.source} target="_blank" rel="noreferrer">официальный тариф</a>
            </p>
            {crm.configs.map((config) => (
              <p key={`${crm.crm}-${config.name}`}>
                {config.name}: {config.price} ₽ {config.period}
                {config.promoPrice ? ` (акция: ${config.promoPrice} ₽)` : ''}
                {config.oldPrice ? ` (старая цена: ${config.oldPrice} ₽)` : ''}
              </p>
            ))}
            {crm.note && <p className="info">{crm.note}</p>}
          </div>
        ))}
      </div>

      <form className="form" onSubmit={submit}>
        <input
          placeholder="Название CRM"
          value={form.name}
          onChange={(e) => setForm({ ...form, name: e.target.value })}
          required
        />
        <input
          placeholder="Описание"
          value={form.description}
          onChange={(e) => setForm({ ...form, description: e.target.value })}
        />
        <input
          type="number"
          min="0"
          placeholder="Базовая цена"
          value={form.base_price}
          onChange={(e) => setForm({ ...form, base_price: e.target.value })}
        />
        <input
          type="url"
          placeholder="Сайт"
          value={form.website_url}
          onChange={(e) => setForm({ ...form, website_url: e.target.value })}
        />
        <button type="submit">{editingId ? 'Сохранить изменения' : 'Добавить CRM'}</button>
        <button type="button" onClick={importDefaultCrm}>Импортировать Bitrix24 / amoCRM / Мегаплан</button>
      </form>

      {error && <p className="error">{error}</p>}
      {info && <p className="info">{info}</p>}

      <div className="table-wrapper">
        <table>
          <thead>
            <tr>
              <th>Название</th>
              <th>Описание</th>
              <th>Базовая цена</th>
              <th>Сайт</th>
              <th>Действия</th>
            </tr>
          </thead>
          <tbody>
            {list.map((item) => (
              <tr key={item.id}>
                <td>{item.name}</td>
                <td>{item.description}</td>
                <td>{item.base_price}</td>
                <td>
                  {item.website_url && (
                    <a href={item.website_url} target="_blank" rel="noreferrer">
                      Открыть
                    </a>
                  )}
                </td>
                <td className="actions">
                  <button type="button" onClick={() => edit(item)}>Изменить</button>
                  <button type="button" className="danger" onClick={() => remove(item.id)}>
                    Удалить
                  </button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </section>
  );
};

export default CrmPage;
